<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <meta name="description" content="AIRGOS - Votre partenaire logistique pour des solutions aéroportuaires intelligentes." />
  <title>AIRGOS - Solution Digitale Aéroportuaire</title>

  <link href="https://unpkg.com/aos@2.3.1/dist/aos.css" rel="stylesheet" />
  <link href="https://fonts.googleapis.com/css2?family=Roboto:wght@400;700&display=swap" rel="stylesheet" />

  <style>
    /* ===== Reset & Tokens ===== */
    *,*::before,*::after{box-sizing:border-box}
    html{scroll-behavior:smooth}
    body{margin:0;font-family:Roboto,system-ui,-apple-system,Segoe UI,Arial,sans-serif;line-height:1.6;color:#0f172a;background:#fff}
    img{max-width:100%;height:auto;display:block}
    a{text-decoration:none}
    :root{
      --brand:#0b3a69;
      --brand-dark:#072a4a;
      --muted:#64748b;
      --ink:#0f172a;
      --card:#f8fafc;
      --line:#e2e8f0;
      --container:1200px;
      --pad:clamp(16px,2vw,24px);
      --radius:12px;
      --shadow:0 10px 30px rgba(0,0,0,.15);
      --header-h:64px;
    }
    .container{width:min(92%,var(--container));margin-inline:auto}

    /* ===== Header & Nav ===== */
    header#header{
      position:fixed;inset-block-start:0;inset-inline:0;height:var(--header-h);
      background:rgba(11,58,105,.96);color:#fff;z-index:1000;
      backdrop-filter:saturate(140%) blur(6px);
      box-shadow:0 1px 0 rgba(0,0,0,.1);
    }
    .nav-wrap{height:100%;display:flex;align-items:center;gap:16px;padding-inline:var(--pad)}
    .brand{color:#fff;font-weight:700;letter-spacing:.3px}
    nav#mainnav{display:flex;gap:20px;margin-inline-start:auto}
    nav#mainnav a{color:#fff;padding:.5rem .25rem;white-space:nowrap}
    nav#mainnav a:hover, nav#mainnav a:focus-visible{text-decoration:underline;outline:none}

    .nav-toggle{
      display:none;inline-size:40px;block-size:40px;margin-inline-start:auto;
      background:none;border:0;cursor:pointer
    }
    .nav-toggle .bar{display:block;inline-size:24px;block-size:2px;background:#fff;margin:6px auto;border-radius:1px}

    @media (max-width:900px){
      nav#mainnav{
        position:fixed;inset-block-start:var(--header-h);inset-inline:0;
        background:var(--brand);
        flex-direction:column;gap:0;padding:.5rem 0;display:none;
        max-block-size:calc(100dvh - var(--header-h));overflow:auto
      }
      nav#mainnav.open{display:flex}
      nav#mainnav a{padding:12px 16px}
      .nav-toggle{display:inline-flex}
    }
    body.no-scroll{overflow:hidden}
    header.scrolled{background:rgba(11,58,105,1)}

    /* ===== Layout ===== */
    main{padding-block-start:calc(var(--header-h) + 16px)}
    section{padding:clamp(40px,6vw,72px) 0}
    .section-title{font-size:clamp(22px,3.2vw,36px);text-align:center;margin:0 0 12px;color:var(--brand)}
    .section-sub{font-size:clamp(18px,2.2vw,24px);margin:24px 0 8px;color:var(--brand)}
    .lead{font-size:clamp(16px,2.2vw,20px);color:#1f2937}

    /* Two-column blocks (collapse on mobile) */
    .two-col{display:grid;grid-template-columns:2fr 1fr;gap:clamp(16px,3vw,28px);align-items:start}
    .two-col .media{align-self:start}
    @media (max-width:900px){.two-col{grid-template-columns:1fr}}

    /* ===== Hero ===== */
    .hero{
      min-block-size:60vh;display:grid;place-items:center;position:relative;text-align:center;color:#fff;
      background:#111 url('hero-bg.jpg') center/cover no-repeat;
    }
    .hero::after{content:"";position:absolute;inset:0;background:rgba(0,0,0,.45)}
    .hero > .container{position:relative}
    .hero h1{font-size:clamp(28px,4vw,44px);margin:0 0 .5rem}
    .hero p{margin:0 auto;max-inline-size:800px}
    @media (min-width:901px){ .hero{background-attachment:fixed} }

    /* ===== Presentation band ===== */
    .presentation-bg{
      background:url('18C.png') center/cover no-repeat;position:relative;color:#fff;display:flex;align-items:center;min-block-size:40vh
    }
    .presentation-bg::before{content:"";position:absolute;inset:0;background:rgba(0,0,0,.5)}
    .presentation-bg .container{position:relative}

    /* Media hero (images) */
    .media-hero img{border-radius:var(--radius);box-shadow:var(--shadow)}

    /* Pills */
    .pill-list{display:flex;flex-wrap:wrap;gap:8px;justify-content:center;margin-top:12px}
    .pill-list span{background:rgba(11,58,105,.08);color:var(--brand);padding:6px 10px;border-radius:999px;font-weight:700;font-size:14px}

    /* Contact form */
    .contact-form{max-inline-size:640px;margin-inline:auto}
    .contact-form label{display:block;font-weight:700;margin:.5rem 0 .25rem}
    .contact-form input,.contact-form textarea{inline-size:100%;padding:.75rem;border:1px solid var(--line);border-radius:10px}
    .contact-form button{margin-top:.5rem;background:var(--brand);color:#fff;border:0;border-radius:10px;padding:.75rem 1.25rem;cursor:pointer}
    .contact-form button:hover{background:var(--brand-dark)}

    /* KPI + Testimonials */
    .kpi-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:16px;margin-top:12px}
    @media(max-width:900px){.kpi-grid{grid-template-columns:1fr 1fr}}
    .kpi-card{background:var(--card);border:1px solid var(--line);border-radius:var(--radius);padding:16px;text-align:center}
    .kpi-card .val{font-size:clamp(22px,4vw,34px);font-weight:800;color:var(--brand)}
    .kpi-card .lbl{color:var(--muted);font-weight:600;font-size:14px}

    .testimonials{display:grid;gap:16px;grid-template-columns:1fr 1fr;margin-top:16px}
    @media(max-width:900px){.testimonials{grid-template-columns:1fr}}
    .quote{background:#0b3a690d;border-left:4px solid var(--brand);padding:12px 16px;border-radius:var(--radius)}
    .quote strong{display:block;margin-bottom:4px;color:var(--brand)}
    .quote small{color:#475569}

    /* Logos */
    .logos{display:flex;flex-wrap:wrap;gap:16px;justify-content:center;align-items:center;margin-top:12px}
    .logos img{inline-size:90px}

    /* Footer */
    footer{background:#f2f5f9;padding:24px 0;color:#334155;text-align:center}
    footer p{margin:.25rem 0}

    /* Accessibility / Motion */
    @media (prefers-reduced-motion:reduce){
      *{animation:none!important;transition:none!important;scroll-behavior:auto!important}
    }
  </style>
</head>
