  <!-- ===== Scripts ===== -->
  <script src="https://unpkg.com/aos@2.3.1/dist/aos.js"></script>
  <script>
    AOS.init({ once:true, duration:800 });

    // Header background on scroll
    const hdr = document.getElementById('header');
    window.addEventListener('scroll', () => {
      const y = window.pageYOffset || document.documentElement.scrollTop;
      hdr.classList.toggle('scrolled', y > 50);
    });

    // Hamburger
    const btn = document.querySelector('.nav-toggle');
    const nav = document.getElementById('mainnav');

    const closeNav = () => {
      btn.setAttribute('aria-expanded','false');
      nav.classList.remove('open');
      document.body.classList.remove('no-scroll');
    };

    btn.addEventListener('click', () => {
      const open = btn.getAttribute('aria-expanded') === 'true';
      btn.setAttribute('aria-expanded', String(!open));
      nav.classList.toggle('open', !open);
      document.body.classList.toggle('no-scroll', !open);
    });

    // Fermer en cliquant dehors, sur un lien, ou via Échap
    document.addEventListener('click', (e) => {
      if (nav.classList.contains('open') && !nav.contains(e.target) && !btn.contains(e.target)) closeNav();
      if (e.target.closest('#mainnav a')) closeNav();
    });
    document.addEventListener('keydown', (e) => { if (e.key === 'Escape') closeNav(); });
  </script>
